import React, { useState } from 'react'
import { useSelector } from 'react-redux';



import { CloseModal} 
from '../../../actions/common'
import { selectObserveScreenWidth } from '../../../store/qvamarketsSlice';
import { gen12CodeId, getPaymentsType, getStore, isMobile, ObjectKeys, translatetext, updStore } from '../../../store/Util';


import {
  BTNH_Cmpt,
  Cmpt_CircleTabrt,
  Icon_Cmpt,
}  from  '../../components'



const BTNH = BTNH_Cmpt();
const Icon2 = Icon_Cmpt();

const CircleTabrt = Cmpt_CircleTabrt();




const UpdateInventoryModal = (props) => {
  const { data } = props;
  const {  modalID, item, userId  } = data;
  const widthScreen = useSelector(selectObserveScreenWidth);

  const [obs, setObs] = useState(0);

  const remove = async () => {   
    if(typeof props.confirm === "function"){
      props.confirm();
    }
    CloseModal({id:modalID});
  }

  const reject = async () => {   
    if(typeof props.reject === "function"){
      props.reject();
    }
    CloseModal({id:modalID});
  }

  const clear = (v,f) => {
    CloseModal({id:modalID});
  }

 

  return (
    <div {...modalID?{"dialog-key-id":modalID}:""}  className={`pym81b sendBx upd_alert_bx modal_max_content conditions ${isMobile()?"is_mobile":""}`}>
      <style>
        {`
        .palette{
          --base-color: rgb(21, 100, 191,1);
          --base-color-gradient: 21, 100, 191;
        }
        `}
        </style>
        <div className={` _dsplFlx conditions`}>
            <div  className={`delete_alert_t1 confAppnt`}>
            {translatetext(215)}
            </div>
            <div className={`flexSpace`}/>  
            <div  className={`closeBtn`} onClick={clear} >
              <Icon2 
                name={"cancel"} 
                color={"#262626"}
              />
            </div>
        </div>
        <div className={`delete_alert_t2 conditions`}>
          <p>
            {translatetext(214)}
          </p>
        </div>
        <div className={`payment_type `}>
          <p>
            {translatetext(216)}
          </p>
        </div>
        

        <div className={`payment_options conditions _dsplFlx spaceAround`}>
          {getPaymentsType() && ObjectKeys(getPaymentsType()).map(pId=>{
            let itm = getPaymentsType()[pId];
            return (
              <div 
                className={`_${pId} ${getStore("paymentType")===pId?"isActive":""}`}
                onClick={()=>{
                  updStore("paymentType", pId);
                  setObs(gen12CodeId())
                }}
              >
              <CircleTabrt 
                src={itm.logo} 
                txt={itm.title}
              />
              </div>
            )
          })}
        </div>
        <div style={{ marginTop: "40px"}}></div>

        <div className={`sendBtn _dsplFlx spaceAround `}>
          <div className={`fieldPadding _MrgV`} style={{ marginTop: "10px"}}>
            <span onClick={()=>reject()}>
              <BTNH theme={``} title={ translatetext(217)} />
            </span>
          </div>
          {getStore("paymentType")?
          <div className={`fieldPadding _MrgV`} style={{ marginTop: "10px"}}>
            <span onClick={()=>remove()}>
              <BTNH theme={`light_blue`} title={translatetext(219)}/>
            </span>
          </div>
          :null}
        </div>
    </div>
    )
}


export default UpdateInventoryModal